  1	import * as React from 'react';
  2	import { useODFNamespaceSelector } from '@odf/core/redux';
  3	import { useGetExternalClusterDetails } from '@odf/core/redux/utils';
  4	import { BreakdownCardBody } from '@odf/shared/dashboards/breakdown-card/breakdown-body';
  5	import { getSelectOptions } from '@odf/shared/dashboards/breakdown-card/breakdown-dropdown';
  6	import {
  7	  useCustomPrometheusPoll,
  8	  usePrometheusBasePath,
  9	} from '@odf/shared/hooks/custom-prometheus-poll';
 10	import {
 11	  BreakdownCardFields,
 12	  BreakdownCardFieldsWithParams,
 13	} from '@odf/shared/queries';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import {
 16	  humanizeBinaryBytes,
 17	  getInstantVectorStats,
 18	  sortInstantVectorStats,
 19	} from '@odf/shared/utils';
 20	import {
 21	  Card,
 22	  CardBody,
 23	  CardHeader,
 24	  CardTitle,
 25	  MenuToggle,
 26	  MenuToggleElement,
 27	  SelectList,
 28	  Select,
 29	  SelectProps,
 30	} from '@patternfly/react-core';
 31	import { useStorageClassQueryFilter } from '../../hooks';
 32	import { getBreakdownMetricsQuery } from '../../queries';
 33	import { getStackChartStats } from '../../utils/metrics';
 34	import {
 35	  NamespaceDropdown,
 36	  DescriptionText,
 37	  TitleWithHelp,
 38	} from '../persistent-internal/capacity-breakdown-card/capacity-breakdown-card';
 39	import '../persistent-internal/capacity-breakdown-card/capacity-breakdown-card.scss';
 40	
 41	export const BreakdownCard: React.FC = () => {
 42	  const { t } = useCustomTranslation();
 43	  const [metricType, setMetricType] = React.useState<
 44	    BreakdownCardFields | BreakdownCardFieldsWithParams
 45	  >(BreakdownCardFields.PROJECTS);
 46	  const [isOpenBreakdownSelect, setBreakdownSelect] = React.useState(false);
 47	  const [pvcNamespace, setPVCNamespace] = React.useState('');
 48	
 49	  const { clusterNamespace: clusterNs } = useGetExternalClusterDetails();
 50	  const { odfNamespace } = useODFNamespaceSelector();
 51	
 52	  const [scQueryfilter, scQueryfilterLoaded, scQueryfilterError] =
 53	    useStorageClassQueryFilter(clusterNs);
 54	
 55	  const { queries, model, metric } = getBreakdownMetricsQuery(
 56	    metricType,
 57	    scQueryfilter,
 58	    pvcNamespace,
 59	    true
 60	  );
 61	  const queryKeys = Object.keys(queries);
 62	
 63	  const [byUsed, byUsedError, byUsedLoading] = useCustomPrometheusPoll({
 64	    endpoint: 'api/v1/query' as any,
 65	    query: queries[queryKeys[0]],
 66	    basePath: usePrometheusBasePath(),
 67	  });
 68	  const [totalUsed, totalUsedError, totalUsedLoading] = useCustomPrometheusPoll(
 69	    {
 70	      endpoint: 'api/v1/query' as any,
 71	      query: queries[queryKeys[1]],
 72	      basePath: usePrometheusBasePath(),
 73	    }
 74	  );
 75	
 76	  const queriesLoadError = byUsedError || totalUsedError || scQueryfilterError;
 77	  const queriesDataLoaded =
 78	    !byUsedLoading && !totalUsedLoading && scQueryfilterLoaded;
 79	
 80	  const humanize = humanizeBinaryBytes;
 81	  const top6MetricsData = getInstantVectorStats(byUsed, metric);
 82	  const top5SortedMetricsData = sortInstantVectorStats(top6MetricsData);
 83	  const top5MetricsStats = getStackChartStats(top5SortedMetricsData, humanize);
 84	  const metricTotal = totalUsed?.data?.result[0]?.value[1];
 85	
 86	  const handleMetricsChange: SelectProps['onSelect'] = (_e, breakdown) => {
 87	    setMetricType(breakdown as BreakdownCardFields);
 88	    setBreakdownSelect(!isOpenBreakdownSelect);
 89	  };
 90	
 91	  const dropdownOptions = [
 92	    {
 93	      name: t('Projects'),
 94	      id: BreakdownCardFields.PROJECTS,
 95	    },
 96	    {
 97	      name: t('Storage Classes'),
 98	      id: BreakdownCardFields.STORAGE_CLASSES,
 99	    },
100	    {
101	      name: t('Pods'),
102	      id: BreakdownCardFields.PODS,
103	    },
104	    {
105	      name: t('PersistentVolumeClaims'),
106	      id: BreakdownCardFieldsWithParams.PVCS,
107	    },
108	  ];
109	
110	  const breakdownSelectItems = getSelectOptions(dropdownOptions);
111	
112	  const onToggleClick = () => {
113	    setBreakdownSelect(!isOpenBreakdownSelect);
114	  };
115	
116	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
117	    <MenuToggle
118	      ref={toggleRef}
119	      onClick={onToggleClick}
120	      isExpanded={isOpenBreakdownSelect}
121	      className="ceph-capacity-breakdown-card-header__dropdown"
122	      aria-label={t('Break By Dropdown')}
123	      isFullWidth
124	    >
125	      {metricType}
126	    </MenuToggle>
127	  );
128	
129	  return (
130	    <Card>
131	      <CardHeader className="ceph-capacity-breakdown-card__header">
132	        <CardTitle>
133	          <TitleWithHelp />
134	        </CardTitle>
135	        <Select
136	          onSelect={handleMetricsChange}
137	          isOpen={isOpenBreakdownSelect}
138	          selected={t('{{metricType}}', { metricType })}
139	          toggle={toggle}
140	          shouldFocusToggleOnSelect
141	          popperProps={{ width: 'trigger' }}
142	          onOpenChange={(isOpen) => setBreakdownSelect(isOpen)}
143	        >
144	          <SelectList>{breakdownSelectItems}</SelectList>
145	        </Select>
146	      </CardHeader>
147	      {metricType === BreakdownCardFieldsWithParams.PVCS && (
148	        <NamespaceDropdown setPVCNamespace={setPVCNamespace} />
149	      )}
150	      <CardBody className="ceph-capacity-breakdown-card__body">
151	        <BreakdownCardBody
152	          isLoading={!queriesDataLoaded}
153	          hasLoadError={queriesLoadError}
154	          metricTotal={metricTotal}
155	          capacityUsed={metricTotal}
156	          top5MetricsStats={top5MetricsStats}
157	          metricModel={model}
158	          humanize={humanize}
159	          odfNamespace={odfNamespace}
160	        />
161	        {metricType === BreakdownCardFieldsWithParams.PVCS &&
162	          !queriesLoadError &&
163	          top5MetricsStats.length > 0 && <DescriptionText />}
164	      </CardBody>
165	    </Card>
166	  );
167	};
168	
169	export default BreakdownCard;

