 1	import * as React from 'react';
 2	import { SelectOption, SelectGroup, SelectList } from '@patternfly/react-core';
 3	
 4	type GroupedSelectItems = {
 5	  group: string;
 6	  items: { name: string; id: string }[];
 7	}[];
 8	
 9	export const getSelectOptions = (
10	  selectItems: { name: string; id: string }[]
11	): React.ReactElement[] =>
12	  selectItems.map(({ id, name }) => (
13	    <SelectOption key={id} value={id}>
14	      {name}
15	    </SelectOption>
16	  ));
17	
18	export const getGroupedSelectOptions = (
19	  groupedSelectItems: GroupedSelectItems
20	): React.ReactElement[] =>
21	  groupedSelectItems.map(({ group, items }) => (
22	    <SelectGroup key={group} label={group}>
23	      <SelectList>{getSelectOptions(items)}</SelectList>
24	    </SelectGroup>
25	  ));
26	
27	export const getOptionsMenuItems = (
28	  dropdownItems: GroupedSelectItems,
29	  selectedItems: string[]
30	) => {
31	  return dropdownItems.map(({ group, items }) => (
32	    <SelectGroup
33	      className="nb-data-consumption-card__dropdown-item--hide-list-style"
34	      key={group}
35	      label={group}
36	    >
37	      <SelectList>
38	        {items.map((item) => (
39	          <SelectOption
40	            isSelected={selectedItems.includes(item.id)}
41	            id={item.id}
42	            key={item.id}
43	            value={item.id}
44	          >
45	            {item.name}
46	          </SelectOption>
47	        ))}
48	      </SelectList>
49	    </SelectGroup>
50	  ));
51	};

